sql:
SELECT candidate_id, SUM(amount) AS total_expenditures
FROM expenditures
GROUP BY candidate_id;

SELECT COUNT(*) 
FROM historical_expenditures 
WHERE expenditure_id = '<specific_expenditure_id>';

SELECT COUNT(*) AS total_count
FROM candidates_committees
WHERE association_type = 'candidate-committee';

SELECT AVG(candidate_count) as average_candidate_count
FROM (
  SELECT committee_id, COUNT(candidate_id) as candidate_count
  FROM candidates_committees
  GROUP BY committee_id
);

external_knowledge:
- Financial outflows are represented by expenditures;
- Financial inflows are represented by donations;
- The metaphorical 'pouring and receiving streams' symbolizes the expenditures and donations.

sql:
SELECT candidate_name, party
FROM candidates
WHERE candidate_id IN (
    SELECT DISTINCT candidate_id
    FROM contributions
);

external_knowledge:
- A non-zero expenditure signifies a transaction of significance, not just a formality.;
- The requirement to match the date of the expenditure with the audit date implies that we are looking at expenditures made specifically on the day of an audit.;
- The role 'candidate' identifies the individual as a person running for an office or position, and their associated audit details are crucial for transparency and accountability.;

sql:
SELECT DISTINCT committee_name
FROM committees
WHERE party = 'Democratic';

SELECT eo.election_official_name, eo.email
FROM election_officials eo
JOIN contributions co ON eo.election_official_id = co.candidate_id;
